// friday13.cs — Friday the 13th in the proleptic Gregorian calendar

// Find the earliest Friday the 13th starting from 0001-01-01
DateTime earliest = DateTime.MinValue;
for (int year = 1; year <= 9999; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            earliest = d;
            goto found;
        }
    }
}
found:
Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// Count Friday the 13ths in one full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}
Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

